const SC = {
  olive:     "#1D4ED8",   // ブルー（ヘッダー・枠線）
  oliveLight:"#3B82F6",   // ミディアムブルー
  beige:     "#EFF6FF",   // 薄いブルー（行背景）
  beigeDeep: "#DBEAFE",   // 少し深いブルー（交互行）
  salmon:    "#2563EB",   // ブルー（道標アクセント）
  cream:     "#F8FAFF",   // ページ背景
  brown:     "#1E293B",   // ダークネイビー（テキスト）
  end:       "#1D4ED8",   // ブルー（終了行・お楽しみ行）
};

// 道標アイコン（SVG）
function SignPost({ color = SC.salmon }) {
  return (
    <svg width="18" height="20" viewBox="0 0 18 20" fill="none" style={{ flexShrink: 0, marginTop: 1 }}>
      <rect x="8" y="0" width="2" height="20" rx="1" fill={color} />
      <polygon points="1,4 14,4 17,7 14,10 1,10" fill={color} />
      <polygon points="17,11 4,11 1,14 4,17 17,17" fill="#A0522D" opacity="0.7" />
    </svg>
  );
}

function ScheduleTab({ schedule, onChange }) {
  const [editingItem, setEditingItem] = useState(null);
  const [addingDay, setAddingDay] = useState(null);
  const [newItem, setNewItem] = useState({ time: "", title: "", note: "", icon: "📌" });

  function saveEdit(dayId, itemId, field, val) {
    onChange(schedule.map(d => d.id !== dayId ? d : {
      ...d, items: d.items.map(i => i.id !== itemId ? i : { ...i, [field]: val })
    }));
  }
  function deleteItem(dayId, itemId) {
    onChange(schedule.map(d => d.id !== dayId ? d : {
      ...d, items: d.items.filter(i => i.id !== itemId)
    }));
  }
  function addItem(dayId) {
    if (!newItem.title) return;
    onChange(schedule.map(d => d.id !== dayId ? d : {
      ...d, items: [...d.items, { ...newItem, id: Date.now() }]
    }));
    setNewItem({ time: "", title: "", note: "", icon: "📌" });
    setAddingDay(null);
  }

  const isEndRow = (title) => title.includes("終了") || title.includes("解散") || title.includes("お楽しみ");

  // 日ごとの写真
  const dayPhotos = {
    1: [
      { src: IMG_FIRST, cap: "FIRST本社（出発地点）" },
      { src: IMG_GENKAI, cap: "玄海海中展望塔 内部" },
      { src: IMG_HOTEL, cap: "ガーデンテラス佐賀ホテル" },
    ],
    2: [
      { src: IMG_YOBUKO, cap: "呼子朝市" },
      { src: IMG_YOBUKO_ST, cap: "呼子朝市通り" },
    ],
  };

  const [editingNote, setEditingNote] = useState(null); // `${dayId}-${itemId}`

  return (
    <div style={{ background: SC.cream, minHeight: "100%", padding: "18px 14px", fontFamily: "'Hiragino Kaku Gothic ProN','Noto Sans JP',sans-serif" }}>
      {schedule.map(day => (
        <div key={day.id} style={{ marginBottom: 28 }}>

          {/* ── 日付ヘッダー（しおり風：道標＋濃いオリーブ） ── */}
          <div style={{ display: "flex", alignItems: "center", gap: 0, marginBottom: 10 }}>
            {/* 道標アイコン */}
            <div style={{ position: "relative", width: 36, height: 36, flexShrink: 0 }}>
              <svg width="36" height="36" viewBox="0 0 36 36">
                <rect x="16" y="0" width="4" height="36" rx="2" fill={SC.salmon} />
                <polygon points="2,8 28,8 34,14 28,20 2,20" fill={SC.salmon} />
                <polygon points="34,21 8,21 2,27 8,33 34,33" fill="#A0522D" opacity="0.75" />
              </svg>
            </div>
            {/* Schedule ラベル */}
            <div style={{ background: SC.olive, color: "#fff", padding: "7px 18px 7px 10px",
              fontStyle: "italic", fontSize: 18, fontWeight: 800, letterSpacing: 1,
              clipPath: "polygon(0 0, 95% 0, 100% 50%, 95% 100%, 0 100%)",
              marginLeft: 4 }}>
              Schedule
            </div>
            {/* 日付バッジ */}
            <div style={{ background: SC.oliveLight, color: "#fff",
              padding: "6px 14px", fontSize: 13, fontWeight: 700,
              marginLeft: 8, borderRadius: 4 }}>
              {day.date}
            </div>
          </div>

          {/* ── 行リスト ── */}
          <div style={{ border: `2px solid ${SC.olive}`, borderRadius: 6, overflow: "hidden" }}>
            {day.items.map((item, idx) => {
              const isEnd = isEndRow(item.title);
              const rowBg = isEnd ? "#DBEAFE"
                : idx % 2 === 0 ? SC.beige : SC.beigeDeep;
              return (
                <div key={item.id} style={{
                  background: rowBg,
                  borderBottom: `1px solid ${SC.oliveLight}44`,
                  display: "flex", alignItems: "flex-start",
                  padding: "9px 10px", gap: 8,
                }}>
                  {/* 時刻 */}
                  <div style={{
                    minWidth: 42, textAlign: "right",
                    fontSize: 14, fontWeight: 800,
                    color: isEnd ? SC.end : SC.olive,
                    fontFamily: "'Georgia', serif",
                    flexShrink: 0, paddingTop: 2,
                  }}>
                    {item.time}
                  </div>
                  {/* 区切り線 */}
                  <div style={{ width: 1, minHeight: 28, background: SC.olive + "55", flexShrink: 0, alignSelf: "stretch" }} />
                  {/* 内容 */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {editingItem === `${day.id}-${item.id}` ? (
                      <input defaultValue={item.title}
                        onBlur={e => { saveEdit(day.id, item.id, "title", e.target.value); setEditingItem(null); }}
                        autoFocus style={{ fontSize: 13, fontWeight: 600,
                          border: `1px solid ${SC.olive}`, borderRadius: 4,
                          padding: "2px 6px", outline: "none", width: "100%", background: "#fff" }} />
                    ) : (
                      <span style={{
                        fontSize: 13, fontWeight: isEnd ? 700 : 600,
                        color: isEnd ? SC.end : SC.brown,
                        fontStyle: isEnd ? "italic" : "normal",
                      }}>{item.title}</span>
                    )}
                    {/* メモ：タップで編集 */}
                    {editingNote === `${day.id}-${item.id}` ? (
                      <input
                        defaultValue={item.note}
                        placeholder="メモを入力…"
                        autoFocus
                        onBlur={e => { saveEdit(day.id, item.id, "note", e.target.value); setEditingNote(null); }}
                        onKeyDown={e => { if (e.key === "Enter") { saveEdit(day.id, item.id, "note", e.target.value); setEditingNote(null); }}}
                        style={{ fontSize: 11, color: SC.oliveLight, marginTop: 3,
                          border: `1px solid ${SC.olive}88`, borderRadius: 4,
                          padding: "2px 6px", outline: "none", width: "100%",
                          background: "#fff", display: "block" }} />
                    ) : (
                      <div
                        onClick={() => setEditingNote(`${day.id}-${item.id}`)}
                        style={{ fontSize: 11, marginTop: 3, cursor: "pointer",
                          color: item.note ? SC.oliveLight : SC.olive + "44",
                          fontStyle: item.note ? "normal" : "italic",
                          minHeight: 14 }}>
                        {item.note || "✎ メモを追加…"}
                      </div>
                    )}
                  </div>
                  {/* 操作ボタン */}
                  <div style={{ display: "flex", gap: 1, flexShrink: 0 }}>
                    <button onClick={() => setEditingItem(`${day.id}-${item.id}`)}
                      style={{ background: "none", border: "none", cursor: "pointer", fontSize: 12, color: SC.olive, padding: "2px" }}>✏️</button>
                    <button onClick={() => deleteItem(day.id, item.id)}
                      style={{ background: "none", border: "none", cursor: "pointer", fontSize: 12, color: "#aaa", padding: "2px" }}>🗑️</button>
                  </div>
                </div>
              );
            })}
          </div>

          {/* ── 写真ストリップ ── */}
          {dayPhotos[day.id] && (
            <div style={{ display: "flex", gap: 8, overflowX: "auto", padding: "10px 0 4px",
              scrollbarWidth: "none" }}>
              {dayPhotos[day.id].map((p, i) => (
                <div key={i} style={{ flexShrink: 0, borderRadius: 8, overflow: "hidden",
                  boxShadow: "0 2px 8px rgba(0,0,0,0.18)", position: "relative",
                  width: 140, height: 100 }}>
                  <img src={p.src} alt={p.cap}
                    style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                  <div style={{ position: "absolute", bottom: 0, left: 0, right: 0,
                    background: "linear-gradient(transparent, rgba(0,0,0,0.55))",
                    padding: "14px 6px 4px",
                    fontSize: 9, color: "#fff", fontWeight: 600, lineHeight: 1.3 }}>
                    {p.cap}
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* ── 予定追加 ── */}
          {addingDay === day.id ? (
            <div style={{ background: SC.beige, border: `1px dashed ${SC.olive}`, borderRadius: 6,
              padding: 12, marginTop: 8 }}>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 8 }}>
                <input placeholder="時間" value={newItem.time}
                  onChange={e => setNewItem({ ...newItem, time: e.target.value })}
                  style={{ width: 80, borderRadius: 4, border: `1px solid ${SC.olive}55`,
                    padding: "6px 8px", fontSize: 13 }} />
                <input placeholder="タイトル" value={newItem.title}
                  onChange={e => setNewItem({ ...newItem, title: e.target.value })}
                  style={{ flex: 1, minWidth: 120, borderRadius: 4, border: `1px solid ${SC.olive}55`,
                    padding: "6px 8px", fontSize: 13 }} />
              </div>
              <input placeholder="備考（任意）" value={newItem.note}
                onChange={e => setNewItem({ ...newItem, note: e.target.value })}
                style={{ width: "100%", borderRadius: 4, border: `1px solid ${SC.olive}55`,
                  padding: "6px 8px", fontSize: 13, marginBottom: 8, boxSizing: "border-box" }} />
              <div style={{ display: "flex", gap: 8 }}>
                <button onClick={() => addItem(day.id)}
                  style={{ background: SC.olive, color: "#fff", border: "none", borderRadius: 4,
                    padding: "6px 16px", fontSize: 13, fontWeight: 600, cursor: "pointer" }}>追加</button>
                <button onClick={() => setAddingDay(null)}
                  style={{ background: "#fff", color: SC.olive, border: `1px solid ${SC.olive}55`,
                    borderRadius: 4, padding: "6px 14px", fontSize: 13, cursor: "pointer" }}>キャンセル</button>
              </div>
            </div>
          ) : (
            <button onClick={() => setAddingDay(day.id)}
              style={{ marginTop: 8, width: "100%", background: "none",
                border: `1px dashed ${SC.olive}66`, borderRadius: 6,
                padding: "7px", fontSize: 12, color: SC.olive, cursor: "pointer" }}>
              ＋ 予定を追加
            </button>
          )}
        </div>
      ))}
    </div>
  );
}

function ItineraryTab({ it, onChange }) {
  const [editing, setEditing] = useState(null);

  function edit(path, val) {
    if (path[0] === "transport") {
      onChange({ ...it, transport: it.transport.map(t => t.id !== path[1] ? t : { ...t, value: val }) });
    } else if (path[0] === "hotel") {
      onChange({ ...it, hotel: { ...it.hotel, [path[1]]: val } });
    } else {
      onChange({ ...it, [path[0]]: val });
    }
    setEditing(null);
  }

  const EditField = ({ path, value, multiline }) => {
    const key = path.join("-");
    return editing === key ? (
      multiline ? (
        <textarea defaultValue={value} autoFocus rows={3}
          onBlur={e => edit(path, e.target.value)}
          style={{ fontSize: 13, border: `1px solid ${C.sky}`, borderRadius: 4,
            padding: "4px 6px", outline: "none", width: "100%", resize: "vertical", boxSizing: "border-box" }} />
      ) : (
        <input defaultValue={value} autoFocus
          onBlur={e => edit(path, e.target.value)}
          style={{ fontSize: 13, border: `1px solid ${C.sky}`, borderRadius: 4,
            padding: "3px 6px", outline: "none", width: "100%" }} />
      )
    ) : (
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
        <span style={{ fontSize: 13, color: C.ink, whiteSpace: "pre-wrap", flex: 1 }}>{value}</span>
        <button onClick={() => setEditing(key)}
          style={{ background: "none", border: "none", cursor: "pointer", fontSize: 13, color: C.muted, flexShrink: 0 }}>✏️</button>
      </div>
    );
  };

  return (
    <div style={{ padding: "20px 16px", display: "flex", flexDirection: "column", gap: 14 }}>
      {/* 佐賀県マップ */}
      <div style={{ borderRadius: 14, overflow: "hidden", boxShadow: "0 2px 10px rgba(0,0,0,0.12)" }}>
        <img src={IMG_SAGA_MAP} alt="佐賀県マップ"
          style={{ width: "100%", display: "block", maxHeight: 220, objectFit: "cover", objectPosition: "center" }} />
      </div>
      <Card title="🚌 交通">
        {it.transport.map(t => (
          <div key={t.id} style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 2,
              textTransform: "uppercase", letterSpacing: 1 }}>{t.label}</div>
            <EditField path={["transport", t.id]} value={t.value} />
          </div>
        ))}
      </Card>
      <Card title="🏨 ホテル">
        {[
          { key: "name", label: "ホテル名" },
          { key: "address", label: "住所" },
          { key: "tel", label: "電話番号" },
          { key: "checkIn", label: "チェックイン" },
          { key: "checkOut", label: "チェックアウト" },
          { key: "room", label: "部屋割り" },
        ].map(f => (
          <div key={f.key} style={{ marginBottom: 8 }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 2,
              textTransform: "uppercase", letterSpacing: 1 }}>{f.label}</div>
            <EditField path={["hotel", f.key]} value={it.hotel[f.key]} />
          </div>
        ))}
      </Card>
      <Card title="🚕 連絡先">
        <div>
          <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 2,
            textTransform: "uppercase", letterSpacing: 1 }}>連絡先</div>
          <EditField path={["contact"]} value={it.contact} multiline />
        </div>
      </Card>
    </div>
  );
}

function Card({ title, children }) {
  return (
    <div style={{ background: C.white, borderRadius: 12, padding: 16,
      boxShadow: "0 1px 4px rgba(0,0,0,0.07)", border: `1px solid ${C.border}` }}>
      <div style={{ fontSize: 15, fontWeight: 700, color: C.ink, marginBottom: 12 }}>{title}</div>
      {children}
    </div>
  );
}

