function RoomsTab({ rooms, onChange }) {
  // ゲスト名の入力状態を部屋・スロットごとに管理
  // inputs[roomId][slotIndex] = 入力中の名前
  const [inputs, setInputs] = useState(() => {
    const init = {};
    rooms.forEach(r => {
      init[r.id] = Array.from({ length: r.capacity }, (_, i) => r.guests[i]?.name ?? "");
    });
    return init;
  });

  const totalGuests = rooms.reduce((s, r) => s + r.guests.filter(g => g.name.trim()).length, 0);

  function handleInput(roomId, slotIdx, val) {
    setInputs(prev => ({
      ...prev,
      [roomId]: prev[roomId].map((v, i) => i === slotIdx ? val : v)
    }));
  }

  function handleSave(roomId, slotIdx) {
    const name = (inputs[roomId]?.[slotIdx] ?? "").trim();
    onChange(rooms.map(r => {
      if (r.id !== roomId) return r;
      const guests = Array.from({ length: r.capacity }, (_, i) => {
        const n = (inputs[r.id]?.[i] ?? "").trim();
        return n ? { id: r.guests[i]?.id ?? `${r.id}-${i}`, name: n } : null;
      }).filter(Boolean);
      return { ...r, guests };
    }));
  }

  function clearSlot(roomId, slotIdx) {
    setInputs(prev => ({
      ...prev,
      [roomId]: prev[roomId].map((v, i) => i === slotIdx ? "" : v)
    }));
    onChange(rooms.map(r => {
      if (r.id !== roomId) return r;
      const guests = Array.from({ length: r.capacity }, (_, i) => {
        if (i === slotIdx) return null;
        const n = (inputs[r.id]?.[i] ?? "").trim();
        return n ? { id: r.guests[i]?.id ?? `${r.id}-${i}`, name: n } : null;
      }).filter(Boolean);
      return { ...r, guests };
    }));
  }

  // 8部屋固有カラー
  const ROOM_COLORS = [
    { bg: "#2563EB", light: "#DBEAFE" }, // 青
    { bg: "#16A34A", light: "#DCFCE7" }, // 緑
    { bg: "#DC2626", light: "#FEE2E2" }, // 赤
    { bg: "#D97706", light: "#FEF3C7" }, // オレンジ
    { bg: "#7C3AED", light: "#EDE9FE" }, // 紫
    { bg: "#DB2777", light: "#FCE7F3" }, // ピンク
    { bg: "#0891B2", light: "#CFFAFE" }, // シアン
    { bg: "#65A30D", light: "#ECFCCB" }, // ライムグリーン
  ];

  return (
    <div style={{ padding: "20px 16px" }}>
      {/* サマリー */}
      <div style={{ background: `linear-gradient(135deg, #0EA5E9, #2563EB)`, borderRadius: 12,
        padding: "14px 20px", marginBottom: 22, color: C.white,
        display: "flex", justifyContent: "space-around", textAlign: "center" }}>
        <div>
          <div style={{ fontSize: 26, fontWeight: 800 }}>{rooms.length}</div>
          <div style={{ fontSize: 11, opacity: 0.85 }}>部屋数</div>
        </div>
        <div style={{ width: 1, background: "rgba(255,255,255,0.25)" }} />
        <div>
          <div style={{ fontSize: 26, fontWeight: 800 }}>{totalGuests}</div>
          <div style={{ fontSize: 11, opacity: 0.85 }}>入力済み</div>
        </div>
        <div style={{ width: 1, background: "rgba(255,255,255,0.25)" }} />
        <div>
          <div style={{ fontSize: 26, fontWeight: 800 }}>{16 - totalGuests}</div>
          <div style={{ fontSize: 11, opacity: 0.85 }}>未入力</div>
        </div>
      </div>

      {/* 部屋カード（8色） */}
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {rooms.map((room, idx) => {
          const col = ROOM_COLORS[idx % ROOM_COLORS.length];
          const filledCount = (inputs[room.id] ?? []).filter(v => v.trim()).length;
          const isFull = filledCount >= room.capacity;
          return (
            <div key={room.id} style={{ background: C.white, borderRadius: 12,
              boxShadow: "0 1px 4px rgba(0,0,0,0.07)", border: `1px solid ${C.border}`, overflow: "hidden" }}>
              {/* カラーヘッダー */}
              <div style={{ background: col.bg, padding: "10px 16px",
                display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <span style={{ fontSize: 16 }}>🛏️</span>
                </div>
                <div style={{ background: "rgba(255,255,255,0.25)", borderRadius: 20,
                  padding: "2px 10px", fontSize: 12, fontWeight: 700, color: "#fff" }}>
                  {filledCount}/{room.capacity}名
                  {isFull && <span style={{ marginLeft: 5 }}>✅</span>}
                </div>
              </div>
              {/* 入力スロット */}
              <div style={{ padding: "12px 16px", display: "flex", flexDirection: "column", gap: 8 }}>
                {Array.from({ length: room.capacity }, (_, i) => {
                  const val = inputs[room.id]?.[i] ?? "";
                  return (
                    <div key={i} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ width: 24, height: 24, borderRadius: "50%",
                        background: val.trim() ? col.light : "#F1F5F9",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 11, fontWeight: 700, color: col.bg, flexShrink: 0 }}>
                        {i + 1}
                      </div>
                      <input
                        value={val}
                        placeholder={`宿泊者 ${i + 1} の氏名`}
                        onChange={e => handleInput(room.id, i, e.target.value)}
                        onBlur={() => handleSave(room.id, i)}
                        onKeyDown={e => e.key === "Enter" && handleSave(room.id, i)}
                        style={{
                          flex: 1, borderRadius: 8,
                          border: `1.5px solid ${val.trim() ? col.bg : C.border}`,
                          padding: "8px 12px", fontSize: 13,
                          outline: "none", background: val.trim() ? col.light : C.white,
                          color: C.ink, fontWeight: val.trim() ? 600 : 400,
                          transition: "all 0.15s"
                        }}
                      />
                      {val.trim() && (
                        <button onClick={() => clearSlot(room.id, i)}
                          style={{ background: "none", border: "none", cursor: "pointer",
                            fontSize: 15, color: C.muted, padding: "0 2px" }}>×</button>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ fontSize: 11, color: C.muted, textAlign: "center", marginTop: 14 }}>
        氏名を入力してEnterまたはフォーカスを外すと自動保存されます
      </div>
    </div>
  );
}

