function AttractionsTab() {
  const [open, setOpen] = useState(null);
  const toggle = (id) => setOpen(prev => prev === id ? null : id);

  return (
    <div style={{ padding: "20px 16px", display: "flex", flexDirection: "column", gap: 14 }}>
      {spots.map(s => (
        <div key={s.id} style={{ background: C.white, borderRadius: 14,
          boxShadow: "0 1px 4px rgba(0,0,0,0.08)", border: `1px solid ${C.border}`, overflow: "hidden" }}>
          <button onClick={() => toggle(s.id)} style={{ width: "100%", background: "none", border: "none",
            cursor: "pointer", padding: "16px", textAlign: "left" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <div style={{ width: 44, height: 44, borderRadius: 12, background: s.tagBg,
                display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>
                {s.emoji}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 15, fontWeight: 800, color: C.ink }}>{s.name}</div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 3 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: s.tagColor, background: s.tagBg,
                    borderRadius: 4, padding: "1px 7px" }}>{s.day}</span>
                </div>
              </div>
              <span style={{ fontSize: 20, color: C.muted, transition: "transform 0.2s",
                transform: open === s.id ? "rotate(90deg)" : "rotate(0deg)" }}>›</span>
            </div>
          </button>

          {open === s.id && (
            <div style={{ padding: "0 16px 16px" }}>
              {/* スポット写真 */}
              {s.photo && (() => {
                const photoMap = { IMG_GENKAI: IMG_GENKAI, IMG_YOBUKO: IMG_YOBUKO, IMG_TOSU_OUTLET: IMG_TOSU_OUTLET, IMG_SUIZUKI: IMG_SUIZUKI };
                const src = photoMap[s.photo];
                return src ? (
                  <div style={{ borderRadius: 10, overflow: "hidden", marginBottom: 12,
                    boxShadow: "0 2px 8px rgba(0,0,0,0.12)" }}>
                    <img src={src} alt={s.name}
                      style={{ width: "100%", height: 160, objectFit: "cover", display: "block" }} />
                  </div>
                ) : null;
              })()}
              <div style={{ background: C.surface, borderRadius: 10, padding: "12px 14px",
                marginBottom: 12, border: `1px solid ${C.border}` }}>
                <div style={{ fontSize: 12, lineHeight: 1.9, color: C.muted }}>
                  {[
                    { label: "📍", val: s.address },
                    { label: "📞", val: s.tel },
                    { label: "🕐", val: s.hours },
                    { label: "🚫", val: s.closed },
                    { label: "🅿️", val: s.parking },
                  ].filter(r => r.val).map(r => (
                    <div key={r.label} style={{ display: "flex", gap: 6 }}>
                      <span style={{ flexShrink: 0 }}>{r.label}</span>
                      <span style={{ color: C.ink }}>{r.val}</span>
                    </div>
                  ))}
                </div>
              </div>
              <p style={{ fontSize: 13, color: C.ink, lineHeight: 1.7, margin: "0 0 12px" }}>{s.desc}</p>
              <div style={{ fontSize: 13, fontWeight: 700, color: C.ink, marginBottom: 8 }}>🌟 見どころ</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 12 }}>
                {s.highlights.map(h => (
                  <div key={h.text} style={{ display: "flex", gap: 10, background: s.tagBg,
                    borderRadius: 8, padding: "10px 12px" }}>
                    <span style={{ fontSize: 16, flexShrink: 0 }}>{h.icon}</span>
                    <span style={{ fontSize: 12, color: C.ink, lineHeight: 1.6 }}>{h.text}</span>
                  </div>
                ))}
              </div>
              <div style={{ background: C.sand, borderRadius: 8, padding: "10px 12px",
                fontSize: 12, color: C.ink, lineHeight: 1.6 }}>
                💡 {s.tips}
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

